import dspy
from vex import verify

class HiringSignature(dspy.Signature):
    job_desc = dspy.InputField()
    candidate_profile = dspy.InputField()
    recommendation = dspy.OutputField()

@verify(governance='bias', metric='demographic_parity')
def detect_bias_drift(original_module, optimized_module, test_cases):
    original_scores = []
    optimized_scores = []

    for case in test_cases:
        # Baseline
        original_scores.append(original_module(**case))

        # Optimized
        optimized_scores.append(optimized_module(**case))

    return verify.compare_distributions(original_scores, optimized_scores)

import re
import dspy

def extract_cot_steps(output):
    cot_pattern = r'Step\s*(\d+):\s*(.+?)(?=\nStep|\n\$|$)'
    return re.findall(cot_pattern, output, re.DOTALL)

@verify(safety='logical_consistency')
def detect_cot_violations(module, examples):
    violations = []
    for ex in examples:
        result = module(**ex)
        steps = extract_cot_steps(result.reasoning)

        for i, (step_num, step_text) in enumerate(steps):
            if not verify.logically_consistent(steps[:i+1]):
                violations.append({
                    'example': ex,
                    'failed_step': step_num,
                    'reasoning': steps[:i+1]
                })
    return violations

import numpy as np
from collections import defaultdict

def monitor_composition_shift(composed_module, component_modules, eval_set):
    individual_dists = {}
    composed_dist = []

    # Baseline individual distributions
    for name, module in component_modules.items():
        individual_dists[name] = [module(**ex) for ex in eval_set]

    # Composed distribution
    composed_dist = [composed_module(**ex) for ex in eval_set]

    shift_scores = {}
    for name, dist in individual_dists.items():
        shift = verify.ks_test(dist, composed_dist)
        shift_scores[name] = shift

    return {'shifts': shift_scores, 'alert': any(s > 0.3 for s in shift_scores.values())}

