import dspy
import vex

# 1. Wrap existing DSPy agent with governance
@vex.guardrail('responsible_ai_agent')
class GovernedAgent(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate = dspy.ChainOfThought(HiringSignature)

    @vex.verify(metrics=['bias', 'toxicity', 'factuality'])
    def forward(self, job_desc, candidate_profile):
        return self.generate(
            job_desc=job_desc,
            candidate_profile=candidate_profile
        )

# 2. Monitor optimization process
@vex.track_optimization('hiring_agent_v1')
def safe_optimize(trainset):
    teleprompter = dspy.BootstrapFewShot(metric=vex.governance_metric)
    optimized = teleprompter.compile(GovernedAgent(), trainset)
    vex.approve_deployment(optimized)
    return optimized

# 3. Production monitoring
agent = GovernedAgent()
@vex.monitor_agent('prod_hiring')
def production_forward(**inputs):
    return agent(**inputs)

# Deploy with continuous governance
vex.deploy(production_forward, environment='production')
